const msg = $input.first().json.message.text || '';
const chatId = $input.first().json.message.chat.id;
const firstName = $input.first().json.message.from.first_name || '';
const raw = msg.trim();

// Extract all numbers from the message
const numbers = raw.match(/\d+(?:\.\d{1,2})?/g);

if (!numbers || numbers.length === 0) {
  return [{
    json: {
      chatId,
      reply: '❌ No amounts found in your message.\n\nSend something like:\n• 120 food\n• spent 500 on petrol\n• 40 chai'
    }
  }];
}

const amounts = numbers.map(n => parseFloat(n));
const total = amounts.reduce((sum, a) => sum + a, 0);

// Extract tags
const tags = [];
const tagRegex = /#(\w+)/g;
let tagMatch;
while ((tagMatch = tagRegex.exec(raw)) !== null) {
  tags.push('#' + tagMatch[1]);
}

// Remove numbers and tags to get the text part
const textPart = raw
  .replace(/\d+(?:\.\d{1,2})?/g, '')
  .replace(/#\w+/g, '')
  .replace(/\b(spent|on|for|rs|npr|rupees|rp|paid)\b/gi, '')
  .replace(/\s+/g, ' ')
  .trim();

// Category keyword mapping
const categories = {
  'Food': ['food', 'lunch', 'dinner', 'breakfast', 'snack', 'meal', 'restaurant', 'cafe', 'chai', 'tea', 'coffee', 'momo', 'dal bhat', 'tiffin', 'canteen', 'dal', 'bhat'],
  'Transport': ['petrol', 'diesel', 'fuel', 'uber', 'taxi', 'bus', 'bike', 'ride', 'fare', 'auto', 'grab', 'ola', 'pathao'],
  'Groceries': ['groceries', 'grocery', 'vegetables', 'fruits', 'supermarket', 'bhatbhateni', 'bigmart', 'dairy', 'milk', 'eggs'],
  'Rent': ['rent', 'house rent', 'room rent', 'flat'],
  'Utilities': ['electricity', 'water', 'internet', 'wifi', 'phone', 'mobile', 'recharge', 'bill', 'nea', 'ntc', 'ncell'],
  'Entertainment': ['movie', 'netflix', 'spotify', 'game', 'party', 'outing', 'drinks', 'beer'],
  'Health': ['medicine', 'doctor', 'hospital', 'pharmacy', 'gym', 'medical', 'health', 'dental'],
  'Shopping': ['clothes', 'shoes', 'electronics', 'amazon', 'daraz', 'gadget', 'laptop'],
  'Subscriptions': ['subscription', 'premium', 'membership', 'annual', 'monthly plan'],
  'Education': ['books', 'course', 'tuition', 'class', 'training', 'udemy', 'coursera']
};

let matchedCategory = 'Misc';
let matchedKeyword = '';
const lowerText = textPart.toLowerCase();

for (const [cat, keywords] of Object.entries(categories)) {
  for (const kw of keywords) {
    if (lowerText.includes(kw) && kw.length > matchedKeyword.length) {
      matchedCategory = cat;
      matchedKeyword = kw;
    }
  }
}

// Build note (remaining text after removing matched keyword)
let note = textPart;
if (matchedKeyword) {
  const kwIndex = lowerText.indexOf(matchedKeyword);
  note = (textPart.substring(0, kwIndex) + textPart.substring(kwIndex + matchedKeyword.length)).replace(/\s+/g, ' ').trim();
}

// Build reply
let reply = '📋 Message Breakdown\n';
reply += '━━━━━━━━━━━━━━━\n';
reply += '📨 Original: ' + raw + '\n\n';
reply += '💰 Amount(s): ' + amounts.map(a => 'NPR ' + a.toLocaleString()).join(', ') + '\n';
reply += '📁 Category: ' + matchedCategory + '\n';
if (note) reply += '📝 Note: ' + note + '\n';
if (tags.length > 0) reply += '🏷️ Tags: ' + tags.join(', ') + '\n';
reply += '👤 From: ' + firstName + '\n';
reply += '━━━━━━━━━━━━━━━\n';
reply += '💵 Total: NPR ' + total.toLocaleString();

return [{ json: { chatId, reply } }];
